mapper.select:
SELECT 'SUBJECTIVE' AS card_type, sp.id, s.id AS subject_id, sp.question AS front_text, sp.answer AS back_text, sp.explanation, sp.difficulty FROM subjective_problems sp INNER JOIN subject s ON sp.subject_id = s.id WHERE s.name = #{category}
UNION ALL
SELECT 'FLASHCARD' AS card_type, lc.id, s.id AS subject_id, lc.front_text, lc.back_text, lc.explanation, 0 AS difficulty FROM learning_card lc INNER JOIN subject s ON lc.subject_id = s.id WHERE s.name = #{category}
ORDER BY card_type, id
